import openai

client = openai.OpenAI()

# Pattern 1: Function generation from docstring
def generate_function(description: str, language: str = "python") -> str:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {
                "role": "system",
                "content": f"""You are an expert {language} developer.
Write clean, well-documented code with:
- Type hints
- Docstrings
- Error handling
- Edge case handling"""
            },
            {
                "role": "user",
                "content": description
            }
        ],
        temperature=0.2  # Low temperature for deterministic code
    )
    return response.choices[0].message.content

# Generate a function
result = generate_function("""
Write a function `merge_sorted_lists(list1, list2)` that:
- Takes two sorted lists of integers
- Returns a single sorted list
- Handles empty lists
- O(n) time complexity
- Include test cases""")
print(result)

# Pattern 2: Code translation
def translate_code(code: str, from_lang: str, to_lang: str) -> str:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {
                "role": "system",
                "content": f"Translate {from_lang} to {to_lang}. Preserve logic, add {to_lang}-idiomatic patterns."
            },
            {"role": "user", "content": f"```{from_lang}\n{code}\n```"}
        ]
    )
    return response.choices[0].message.content

# Translate Python to JavaScript
python_code = """
def fibonacci(n: int) -> list[int]:
    if n <= 0:
        return []
    fib = [0, 1]
    for i in range(2, n):
        fib.append(fib[-1] + fib[-2])
    return fib[:n]
"""
print("\nJavaScript version:")
print(translate_code(python_code, "Python", "JavaScript"))

# Pattern 3: Debugging with context
def debug_code(code: str, error: str) -> str:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {
                "role": "system",
                "content": "Debug the code. Explain the root cause, then provide the corrected code."
            },
            {
                "role": "user",
                "content": f"Code:\n```python\n{code}\n```\n\nError: {error}"
            }
        ]
    )
    return response.choices[0].message.content
