import openai
import re
from dataclasses import dataclass
from typing import Optional

client = openai.OpenAI()

@dataclass
class SafetyCheck:
    is_safe: bool
    reason: Optional[str] = None
    category: Optional[str] = None

class ContentModerator:
    """Multi-layer content safety system."""

    def __init__(self):
        self.blocked_patterns = [
            (r"\b(hack|exploit|attack)\b.*\b(system|server|network)\b", "security_misuse"),
            (r"\b(ignore|bypass|override)\b.*\b(safety|rules|guidelines)\b", "jailbreak_attempt"),
        ]

    def check_input(self, user_input: str) -> SafetyCheck:
        """Check user input before sending to model."""
        # Layer 1: Pattern matching
        for pattern, category in self.blocked_patterns:
            if re.search(pattern, user_input, re.IGNORECASE):
                return SafetyCheck(False, f"Blocked pattern: {category}", category)

        # Layer 2: OpenAI Moderation API
        moderation = client.moderations.create(input=user_input)
        if moderation.results[0].flagged:
            flagged_cats = [k for k, v in moderation.results[0].categories.model_dump().items() if v]
            return SafetyCheck(False, f"Flagged: {', '.join(flagged_cats)}", "moderation_api")

        return SafetyCheck(True)

    def check_output(self, model_output: str) -> SafetyCheck:
        """Check model output before returning to user."""
        # Check for hallucination indicators
        hallucination_phrases = [
            "I'm not sure but", "this might be wrong", "I'm guessing",
            "studies show"  # Without citation
        ]
        for phrase in hallucination_phrases:
            if phrase.lower() in model_output.lower():
                return SafetyCheck(True, "Possible hallucination - consider verification", "hallucination")

        # Check for PII leakage
        pii_patterns = [
            (r"\b\d{3}-\d{2}-\d{4}\b", "SSN detected"),
            (r"\b\d{16}\b", "Credit card number detected"),
        ]
        for pattern, reason in pii_patterns:
            if re.search(pattern, model_output):
                return SafetyCheck(False, reason, "pii_leak")

        return SafetyCheck(True)

# Usage in application
moderator = ContentModerator()

user_msg = "How do I secure my web application against attacks?"
input_check = moderator.check_input(user_msg)
print(f"Input safe: {input_check.is_safe}")

response = client.chat.completions.create(
    model="gpt-4o-mini",
    messages=[{"role": "user", "content": user_msg}]
)

output_check = moderator.check_output(response.choices[0].message.content)
print(f"Output safe: {output_check.is_safe}")

# Transparency: disclose AI usage
def add_ai_disclosure(response: str) -> str:
    return f"{response}\n\n---\n_This response was generated by AI. Please verify important information."
